import { getSiteOrigin } from "@/lib/site";

/**
 * LLM / AI クローラ向けのサイト要約（llms.txt 慣習）。
 * NEXT_PUBLIC_SITE_URL に合わせてリンクを出し分ける。
 */
export function GET() {
  const o = getSiteOrigin();
  const body = `# Takarakuji AI (宝くじAI) — ${o}

> English: Unofficial web dashboard for **Japan Numbers4** (ナンバーズ4): official draw results, historical tables, and daily multi-model predictions built from public data. **Not** affiliated with Mizuho Bank or any lottery operator. **Does not** encourage gambling; for information and analysis only.

> 日本語: ナンバーズ4の当選番号・抽選結果の閲覧と、公開データに基づく複数モデルの日次予測をまとめた非公式Webアプリ。購入の推奨や保証は行いません。

## English entry points

- ${o}/en — English overview (for international users & citation)
- ${o}/en/blog — English articles (what is Numbers4, results list, stats/trend, **official verification**)
- ${o}/ — Japanese landing
- ${o}/numbers4 — Numbers4 hub (predictions, stats; UI primarily Japanese)
- ${o}/numbers4/result — Past winning numbers
- ${o}/numbers4/stats — Aggregate statistics (e.g. box ranks)
- ${o}/numbers4/trend — Model performance trends
- ${o}/blog — Articles (Japanese)
- ${o}/faq — FAQ (Japanese)

## Per-draw prediction views

- \`${o}/numbers4/result/{draw_number}\` — Dashboard for a specific draw (predictions ingested as JSON).

## Data & stack (for crawlers)

- Stack: Next.js (App Router), data in Supabase (\`numbers4_draws\`, etc.) synced from official results where applicable.
- Predictions: generated by scheduled jobs; displayed for transparency, not as financial or gambling advice.

## Preferred citation

- Site name: **Takarakuji AI** (Japanese: 宝くじAI)
- Canonical origin: ${o}
`;

  return new Response(body, {
    headers: {
      "Content-Type": "text/plain; charset=utf-8",
      "Cache-Control": "public, s-maxage=3600, stale-while-revalidate=86400",
    },
  });
}

export type BlogPost = {
  slug: string;
  title: string;
  description: string;
  publishedAt: string; // ISO date
  bodyMarkdown: string;
};

export const blogPosts: BlogPost[] = [
  {
    slug: "numbers4-results-and-list",
    title: "ナンバーズ4の当選番号を一覧で見る（宝くじAIの使い方）",
    description:
      "当選番号一覧の見方、ページ送り、スマホでの横スクロールまで。宝くじAIの基本操作をまとめます。",
    publishedAt: "2026-04-01",
    bodyMarkdown: `
## この記事でわかること

- **当選番号一覧**（\`/numbers4/result\`）の読み方
- **回別の予測ページ**への行き方
- スマホで表が見やすい理由（横スクロール）

## 当選番号一覧を開く

トップページの「当選番号一覧」、またはナビの **ナンバーズ4** ゾーンから **当選番号一覧** に進むと、過去の抽選結果が表形式で並びます。各回の当選番号、等級ごとの当選口数・払戻金など、公開されている範囲の情報をまとめて確認できます。

## ページ送りと最新回

一覧はページ分割されている場合があります。画面上のページネーションから、過去にさかのぼって閲覧できます。最新の開催回は、ナンバーズ4の入口ページ（\`/numbers4\`）にも案内があります。

## 回を選んで予測と照合する

各回の行から詳細（予測ハブ）に進むと、その回を対象にした **日次予測**（アンサンブル・手法別・予算プランなど）をまとめて見られます。公式の当選番号がデータベースに取り込まれたあとでは、予測との照合表示も利用できます。

## スマホでの見方

表の列が多いときは、画面を横にスクロールして全列を確認できるようにしています。数字の桁や等級情報を、無理なく追いやすいレイアウトを意識しています。

## 注意（免責）

本サイトは **宝くじの購入を推奨するものではありません**。表示内容は公開データと当サイトで取り込んだ予測データに基づく情報整理であり、将来の当選を保証するものではありません。
`.trim(),
  },
  {
    slug: "numbers4-predictions-stats-trend",
    title: "予測ダッシュボード・統計・トレンドの見方",
    description:
      "アンサンブル予測、ボックス順位の統計、Hot Model トレンド。それぞれのページで何がわかるかを整理しました。",
    publishedAt: "2026-04-02",
    bodyMarkdown: `
## ナンバーズ4ゾーンの3つの柱

1. **予測ダッシュボード**（回別ページ）… その回向けの予測の全体像  
2. **統計**（\`/numbers4/stats\`）… 直近の回を対象に、予測リスト内での「ボックス一致の順位」を集計  
3. **トレンド**（\`/numbers4/trend\`）… 直近の成績から、注目しやすいモデル傾向を可視化  

## 予測ダッシュボードで見るもの

回別ページでは、複数の手法（機械学習・頻度・パターン系など）の出力を一画面に集約しています。**アンサンブル**は複数モデルを組み合わせた結果として表示されることが多く、個別モデルとの違いを比較する土台になります。

## 統計ページの意味

「当選番号が、予測リストのどのあたり（何位以内）にボックス一致として入っていたか」を、期間やモデル別に集めたものです。**当たりやすさを約束する指標ではなく**、あくまで過去の取り込みデータに基づく整理です。モデルごとの特性を比較するのに向いています。

## トレンドページの意味

直近数十回など、限られた範囲の結果から「いま相対的に成績が目立つモデル」を把握するためのビューです。くじの性質上、**短期の結果はばらつきが大きく**、トレンドも状況により変わります。

## データの前提

予測は日次ジョブで生成された JSON を参照して表示します。抽選結果は \`numbers4_draws\` などに同期された公式結果に基づきます。取り込みタイミングによって、画面上の表示が追いつかない間隔がある場合があります。

## まとめ

- **一覧**で結果を追う  
- **回別**で予測の中身を見る  
- **統計・トレンド**でモデル比較のヒントにする  

という流れで使うと、サイト全体の導線がつかみやすくなります。
`.trim(),
  },
];

export function getAllBlogSlugs(): string[] {
  return blogPosts.map((p) => p.slug);
}

export function getPostBySlug(slug: string): BlogPost | undefined {
  return blogPosts.find((p) => p.slug === slug);
}

export function getPostsSortedByDate(): BlogPost[] {
  return [...blogPosts].sort(
