  ].sort((a, b) => b.publishedAt.localeCompare(a.publishedAt));

  const latestDate = allPosts[0]?.publishedAt ?? new Date().toISOString().slice(0, 10);

  const items = allPosts
    .map(
      (post) => `    <item>
      <title><![CDATA[${post.title}]]></title>
