import { getSiteOrigin } from "@/lib/site";

/**
 * LLM / AI クローラ向けのサイト要約（llms.txt 慣習）。
 * NEXT_PUBLIC_SITE_URL に合わせてリンクを出し分ける。
 */
export function GET() {
  const o = getSiteOrigin();
  const body = `# Takarakuji AI (宝くじAI) — ${o}

> English: Unofficial web dashboard for **Japan Numbers4** (ナンバーズ4): official draw results, historical tables, and daily multi-model predictions built from public data. **Not** affiliated with Mizuho Bank or any lottery operator. **Does not** encourage gambling; for information and analysis only.

> 日本語: ナンバーズ4の当選番号・抽選結果の閲覧と、公開データに基づく複数モデルの日次予測をまとめた非公式Webアプリ。購入の推奨や保証は行いません。

## English entry points

- ${o}/en — English overview (for international users & citation)
- ${o}/en/blog — English articles (what is Numbers4, results list, stats/trend, **official verification**)
- ${o}/ — Japanese landing
- ${o}/numbers4 — Numbers4 hub (predictions, stats; UI primarily Japanese)
- ${o}/numbers4/result — Past winning numbers
- ${o}/numbers4/stats — Aggregate statistics (e.g. box ranks)
- ${o}/numbers4/trend — Model performance trends
- ${o}/blog — Articles (Japanese)
- ${o}/faq — FAQ (Japanese)

## Per-draw prediction views

- \`${o}/numbers4/result/{draw_number}\` — Dashboard for a specific draw (predictions ingested as JSON).

## Data & stack (for crawlers)

- Stack: Next.js (App Router), data in Supabase (\`numbers4_draws\`, etc.) synced from official results where applicable.
- Predictions: generated by scheduled jobs; displayed for transparency, not as financial or gambling advice.

## Preferred citation

- Site name: **Takarakuji AI** (Japanese: 宝くじAI)
- Canonical origin: ${o}
`;

  return new Response(body, {
    headers: {
      "Content-Type": "text/plain; charset=utf-8",
      "Cache-Control": "public, s-maxage=3600, stale-while-revalidate=86400",
    },
  });
}

content.text:
Perfect! Now I have a comprehensive understanding. Let me create a detailed summary report of the Numbers4 prediction data structure and flow:

## Comprehensive Report: Numbers4 Prediction Data Structure & Loading

### 1. **Key File Paths**

| File | Purpose |
|------|---------|
| `/lib/numbers4-predictions/load-6949.ts` | Main data loading orchestration |
| `/lib/numbers4-predictions/types.ts` | Type definitions for all prediction data |
| `/lib/numbers4-predictions/prediction-hit-utils.ts` | Hit detection & classification (straight/box) |
| `/lib/numbers4-predictions/box-rank-stats.ts` | Box rank aggregation for statistical analysis |
| `/lib/numbers4-predictions/ensemble-contributors.ts` | Maps ensemble numbers to contributing models |
| `/lib/numbers4-predictions/consensus.ts` | Consensus builder across methods |
| `/lib/numbers4-predictions/summarize-method.ts` | Summarizes method payload into display rows |
| `/lib/numbers4-predictions/ensemble-weight-labels.ts` | Japanese labels for ensemble model names |
| `/app/numbers4/numbers4-predictions-hub.tsx` | Main UI component (23K+ lines) |
| `/supabase/migrations/20260330120000_numbers4_daily_prediction_documents.sql` | Prediction documents DB schema |
| `/supabase/migrations/20260329120000_numbers4_draws.sql` | Official draw results schema |
| `/lib/numbers4.ts` | Draw row type definitions |

---

### 2. **Data Model Overview**

#### **A. Numbers4PredictionBundle (Main Container)**
```typescript
type Numbers4PredictionBundle = {
  source: "database" | "repository_files" | "embedded";
  targetDrawNumber: number;
  ensemble: EnsemblePayload | null;
  budgetPlan: BudgetPlanPayload | null;
  methodRows: MethodPredictionRow[];
};
```
This is the **main data shape** passed through the app. It contains all prediction data for a single draw.

#### **B. EnsemblePayload (Ensemble Predictions)**
```typescript
type EnsemblePayload = {
  draw_number?: number;
  target_draw_number?: number;
  date?: string;
  predictions?: EnsemblePredictionRun[];  // Array of runs (typically 1)
  last_updated?: string;
};

type EnsemblePredictionRun = {
  time?: string;
  time_jst?: string;
  ensemble_weights?: Record<string, number>;      // Model weights (14 models typical)
  top_predictions?: EnsembleTopPrediction[];      // Top candidates (up to ~18 displayed)
  hot_models?: { model: string; score: number }[];
  recent_flow?: { draw: number; model: string; score: number }[];
  next_model_predictions?: { model: string; probability: number; count: number; total: number }[];
};

type EnsembleTopPrediction = {
  rank?: number;
  number?: string;                  // 4-digit prediction
  score?: number;
  similar_patterns?: {              // Nearby candidates
    number?: string;
    description?: string;
    score?: number;
  }[];
};
```
**Key insight**: The hub extracts the **latest run** via `getLatestEnsembleRun()` (last item in predictions array).

#### **C. MethodPredictionRow (Per-Model Predictions)**
```typescript
type MethodPredictionRow = {
  slug: string;                     // e.g., "lightgbm", "box_model"
  relativePath: string | null;      // File path in repo
  runs: number;                     // Execution count
  lastTimeJst: string | null;       // Last execution time
  topNumber: string | null;         // #1 prediction
  topPredictions: MethodTopPrediction[]; // Up to 96 items
};

type MethodTopPrediction = {
  rank?: number;
  number: string;                   // 4-digit normalized
  score: number | null;
};
```
**14 standard model slugs** tracked in `METHOD_SLUGS_FOR_STATS`:
- `box_model`, `ml_neighborhood`, `even_odd_pattern`, `low_sum_specialist`
- `sequential_pattern`, `cold_revival`, `hot_pair`, `box_pattern`
- `digit_freq_box`, `global_frequency`, `lightgbm`, `state_chain`
- `adjacent_digit`, `lgbm_box`

#### **D. BudgetPlanPayload (Recommendation Plans)**
```typescript
type BudgetPlanPayload = {
  target_draw_number?: number;
  created_at?: string;
  planner_version?: string;
  plan_5?: BudgetPlanSlice;      // 5k yen plan
  plan_10?: BudgetPlanSlice;     // 10k yen plan
  hybrid_5?: HybridPlanPayload;  // Box + Mini combo (v15)
  hybrid_10?: HybridPlanPayload;
  expected_value_5?: ExpectedValuePlanSlice;  // EV-focused (v15)
  expected_value_10?: ExpectedValuePlanSlice;
  distributed_plan?: DistributedPlanPayload;  // Multi-session (v15)
  all_mini_5?: AllMiniPlanPayload;            // All-mini strategy (v16)
  set_plan?: SetPlanPayload;                  // Set purchase (v16)
  monthly_simulation?: MonthlySimulationPayload; // Monthly probability (v16)
};

type BudgetRecommendation = {
  priority?: string;              // "1", "2", etc.
  number?: string;                // 4-digit candidate
  buy_method?: string;            // "straight", "box", etc.
  box_type?: string;              // "4連", "3連", etc.
  coverage?: number;              // Unique combinations covered
  marginal_coverage?: number;
  reason?: string;
  expected_value?: number;        // EV in yen (v15)
  box_payout?: number;            // Box payout estimate (v15)
};
```

---

### 3. **Data Loading Flow**

#### **Entry Point: `loadNumbers4PredictionBundle()`**

```typescript
export async function loadNumbers4PredictionBundle(): Promise<Numbers4PredictionBundle> {
  const targetDrawNumber = await resolveTargetDrawNumber();
  const got = await tryLoadBundleForDraw(targetDrawNumber);
  if (got) return got;

  // Fallback to embedded demo data
  return { source: "embedded", targetDrawNumber: FALLBACK_TARGET_DRAW, ... };
}
```

**Load priority** (in `tryLoadBundleForDraw`):
1. **Supabase DB** → `loadBundleFromDatabase(targetDrawNumber)`
2. **Repository JSON files** → `loadBundleFromFilesystem(repoRoot, drawNumber)`
3. **Embedded fallback** → `FALLBACK_ENSEMBLE_6949`, `FALLBACK_BUDGET_6949`

#### **Database Query (loadBundleFromDatabase)**
```typescript
const { data: rows } = await supabase
  .from("numbers4_daily_prediction_documents")
  .select("doc_kind, method_slug, payload, relative_path")
  .eq("target_draw_number", targetDrawNumber);
```
Fetches 3 doc types:
- `doc_kind='ensemble'` (singleton)
- `doc_kind='budget_plan'` (singleton)
- `doc_kind='method'` (multiple, one per model slug)

#### **Filesystem Fallback (loadBundleFromFilesystem)**
Reads from:
- `predictions/daily/numbers4_{drawNumber}.json` → ensemble
- `predictions/daily/budget_plan_{drawNumber}.json` → budget
- `predictions/daily/methods/{slug}/numbers4_{drawNumber}.json` → method rows

#### **Method Payload Summarization (summarizeMethodPayload)**
```typescript
export function summarizeMethodPayload(payload: unknown): MethodPayloadSummary {
