### 4. **Hit/Accuracy Detection**

#### **Core Classification: `classifyHit(prediction, winning)`**
```typescript
export function classifyHit(prediction: string | null, winning: string | null): HitKind {
  const p = normalizeNumbers4(prediction);   // 4-digit pad, remove non-digits
  const w = normalizeNumbers4(winning);
  if (!p || !w) return "none";
  if (p === w) return "straight";
  if (digitsSortedKey(p) === digitsSortedKey(w)) return "box";
  return "none";
}
```
- **"straight"**: Exact 4-digit match (e.g., 1234 == 1234)
- **"box"**: Digit multiset match after sorting (e.g., 1234 ↔ 4321)
- **"none"**: No match

